// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract GoGoPool is ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable ggpToken;
    uint256 public totalStaked;
    mapping(address => uint256) public stakedAmounts;

    event Staked(address indexed user, uint256 amount);
    event Withdrawn(address indexed user, uint256 amount);

    constructor(address _ggpToken) {
        require(_ggpToken != address(0), "GGP token address cannot be zero");
        ggpToken = IERC20(_ggpToken);
    }

    function stake(uint256 amount) external nonReentrant {
        require(amount > 0, "Amount must be greater than zero");
        ggpToken.safeTransferFrom(msg.sender, address(this), amount);
        stakedAmounts[msg.sender] += amount;
        totalStaked += amount;
        emit Staked(msg.sender, amount);
    }

    function withdraw(uint256 amount) external nonReentrant {
        require(amount > 0, "Amount must be greater than zero");
        require(stakedAmounts[msg.sender] >= amount, "Insufficient staked amount");
        stakedAmounts[msg.sender] -= amount;
        totalStaked -= amount;
        ggpToken.safeTransfer(msg.sender, amount);
        emit Withdrawn(msg.sender, amount);
    }

    function getStakedAmount(address user) external view returns (uint256) {
        return stakedAmounts[user];
    }

    function getTotalStaked() external view returns (uint256) {
        return totalStaked;
    }
}
