// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "../GoGoPool.sol";

contract GoGoPoolTest is Test {
    GoGoPool public ggpPool;
    IERC20 public ggpToken;

    function setUp() public {
        ggpToken = IERC20(address(new MockERC20("GGP", "GGP", 1000000)));
        ggpPool = new GoGoPool(address(ggpToken));
    }

    function testStake() public {
        ggpToken.approve(address(ggpPool), 100);
        ggpPool.stake(100);
        assertEq(ggpPool.getStakedAmount(address(this)), 100);
        assertEq(ggpPool.getTotalStaked(), 100);
    }

    function testWithdraw() public {
        ggpToken.approve(address(ggpPool), 100);
        ggpPool.stake(100);
        ggpPool.withdraw(100);
        assertEq(ggpPool.getStakedAmount(address(this)), 0);
        assertEq(ggpPool.getTotalStaked(), 0);
    }

    function testReentrancy() public {
        ggpToken.approve(address(ggpPool), 100);
        ggpPool.stake(100);
        ReentrancyAttack attack = new ReentrancyAttack(address(ggpPool));
        vm.expectRevert("ReentrancyGuard: reentrant call");
        attack.attack();
    }
}

contract ReentrancyAttack {
    GoGoPool public ggpPool;

    constructor(address _ggpPool) {
        ggpPool = GoGoPool(_ggpPool);
    }

    function attack() external {
        ggpPool.stake(1);
    }

    fallback() external {
        ggpPool.withdraw(1);
    }
}

contract MockERC20 is IERC20 {
    string public name;
    string public symbol;
    uint8 public decimals;
    uint256 public totalSupply;
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    constructor(string memory _name, string memory _symbol, uint256 _initialSupply) {
        name = _name;
        symbol = _symbol;
        decimals = 18;
        totalSupply = _initialSupply * 10 ** uint256(decimals);
        balanceOf[msg.sender] = totalSupply;
    }

    function transfer(address recipient, uint256 amount) external override returns (bool) {
        balanceOf[msg.sender] -= amount;
        balanceOf[recipient] += amount;
        emit Transfer(msg.sender, recipient, amount);
        return true;
    }

    function approve(address spender, uint256 amount) external override returns (bool) {
        allowance[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(address sender, address recipient, uint256 amount) external override returns (bool) {
        allowance[sender][msg.sender] -= amount;
        balanceOf[sender] -= amount;
        balanceOf[recipient] += amount;
        emit Transfer(sender, recipient, amount);
        return true;
    }

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
}
